INSERT INTO syntec_suppliers_staging_v2 (DELETED,ACTIVE,SUPPLIER_ID,SUPPLIER_NAME,SHORT_NAME,CLASS_ID,CLASS_COLOUR,PROFILE_1,PROFILE_2,BUSINESS,WEBSITE,SUPPLIER_LOGO_LARGE,SUPPLIER_LOGO_SMALL,SUPPLIER_IMAGE_1,SUPPLIER_IMAGE_2,SUPPLIER_IMAGE_3,SUPPLIER_IMAGE_4,ADDRESS_1,ADDRESS_2,ADDRESS_3,ADDRESS_4,ADDRESS_5,DATE_CREATED,DATE_DELETED,ANCHOR_ID,SUPPLIER_IMAGE_BACKGROUND,SUPPLIER_LOGO_LARGE_SCALE_SMALLER) VALUES ('N','Y','SUP-0014','Trimero Diagnostics',null,null,'#F5C641','<p class="heading-desc t-justify"><span class="main-color"><b>Trimero Diagnostics</b></span> is a 100% Spanish capital founded private company, leader 
					in the field of clinical proteinological diagnostics. The company was created by a team with more 
					than 30 years of experience in the design, manufacturing and 
					distribution of products for clinical analysis laboratories.
					</p>

					<p class="heading-desc t-justify">As a company, we have achieved a high degree of specialization in plasma protein dosing, using both nephelometric 
					and turbidimetric techniques. We have a wide product portfolio, which complements the offer of the main companies 
					in the proteinological sector.
					</p>

					<p class="heading-desc t-justify">The <a href="http:\\www.kloneus.com" target="_blank"><strong><font color="#B2C08B">K</font><font color="#FFBD66">λ</font></strong><font color="#0F8BBE">oneus</font><font color="#000000">®</font></a> line, 
					designed for the quantitative dosing of free light chains (FLC) in serum and urine, 
					is an especially prominent asset in our offer.
					</p>

					<p class="heading-desc t-justify">We operate under the strictest regulations, complying with the European Regulation (EU) 2017/746 on in 
					vitro diagnostic medical devices. We were granted the manufacturer’s license by the 
					<font style="font-style:italic">Agencia Española del Medicamento y Productos Sanitarios (AEMPS)</font>, 
					endorsing the adequacy of our installations, 
					equipment and processes to manufacture reagents for the determination of specific proteins.
					</p>	

					<p class="heading-desc t-justify">We have obtained the ISO Certificate number 
					<a href="../eng/quality-policy.php" target="_blank">Q5 113082 0002 Rev. 00 DIN EN 13485:2016</a> and 
					the EU Quality Management System Certificate (IVDR) 
					number <a href="../eng/quality-policy.php" target="_blank">V12 113082 0001 Rev. 00</a>, 
					both issued by <font style="font-style:italic">TÜV-SÜD Product Service GmbH</font>. These certificates 
					cover the design, development, production, storage and sale of in vitro diagnostic 
					devices, ensuring quality and compliance with current regulations.
					</p>

					<p class="heading-desc t-justify">Trimero Diagnostics has earned the trust of a number of public and private 
					laboratories in Europe, as well as world-leading companies in the clinical 
					diagnostics sector, such as <font style="font-style:italic">Siemens Healthineers</font>, 
					<font style="font-style:italic">Beckman Coulter</font>, <font style="font-style:italic">Abbott</font> 
					and <font style="font-style:italic">The Binding Site</font>, among others. The specialized knowledge and 
					experience of our highly qualified team enables our company to distribute 
					and provide direct support for our cutting-edge products.
					</p>

					<p class="heading-desc t-justify">The company''s global reach extends to clinical proteinology diagnostics 
					through partnerships with leading institutions, distributors and customers worldwide.
					</p>',null,'Syntec Scientific','https://www.3diag.com/eng/company.php','trimero/trimero-logo.png',null,'trimero/trimero-logo_400x267.jpg',null,null,null,null,null,null,null,null,'05-JAN-25',null,'_Trimero','assets/images/Backgrounds/Lab_15_opaque.png','width:90px;');
INSERT INTO syntec_suppliers_staging_v2 (DELETED,ACTIVE,SUPPLIER_ID,SUPPLIER_NAME,SHORT_NAME,CLASS_ID,CLASS_COLOUR,PROFILE_1,PROFILE_2,BUSINESS,WEBSITE,SUPPLIER_LOGO_LARGE,SUPPLIER_LOGO_SMALL,SUPPLIER_IMAGE_1,SUPPLIER_IMAGE_2,SUPPLIER_IMAGE_3,SUPPLIER_IMAGE_4,ADDRESS_1,ADDRESS_2,ADDRESS_3,ADDRESS_4,ADDRESS_5,DATE_CREATED,DATE_DELETED,ANCHOR_ID,SUPPLIER_IMAGE_BACKGROUND,SUPPLIER_LOGO_LARGE_SCALE_SMALLER) VALUES ('N','Y','SUP-0018','Clear Labs',null,null,'#39C5F3','<p class="heading-desc t-justify"><span class="main-color"><b>Clear Labs</b></span> is a leading innovator in next-generation sequencing (NGS) solutions, delivering end-to-end genomic testing platforms for both clinical diagnostics and food safety. Founded in 2014 and headquartered in California, Clear Labs integrates robotics, cloud-based analytics, and AI into its fully automated ClearDx™ system. This platform enables high-throughput, rapid sequencing for pathogen detection, antimicrobial resistance, and genomic surveillance—bringing precision and scalability to sectors ranging from public health to commercial food production.</p>
<p class="heading-desc t-justify">The company’s product suite includes <b>ClearDx™ Clinical</b>, which supports infectious disease testing and outbreak monitoring, and <b>Clear Safety™</b>, which applies the same robust NGS technology to food safety and environmental monitoring. By offering a unified, sample-to-report workflow, Clear Labs minimizes human error and drastically reduces turnaround times, making genomic sequencing both efficient and accessible. Through strategic partnerships with government agencies, hospitals, and enterprise laboratories, Clear Labs is reshaping the role of genomics in both healthcare and industry.</p>',null,'Syntec Scientific','https://www.clearlabs.com/','Clear_Labs/Clear_Labs-logo.png',null,'Clear_Labs/Clear_Labs-logo_400x267.jpg',null,null,null,null,null,null,null,null,'05-JAN-25',null,'_ClearLabs','assets/images/Backgrounds/Lab_49_opaque.png','width:90px;');
INSERT INTO syntec_suppliers_staging_v2 (DELETED,ACTIVE,SUPPLIER_ID,SUPPLIER_NAME,SHORT_NAME,CLASS_ID,CLASS_COLOUR,PROFILE_1,PROFILE_2,BUSINESS,WEBSITE,SUPPLIER_LOGO_LARGE,SUPPLIER_LOGO_SMALL,SUPPLIER_IMAGE_1,SUPPLIER_IMAGE_2,SUPPLIER_IMAGE_3,SUPPLIER_IMAGE_4,ADDRESS_1,ADDRESS_2,ADDRESS_3,ADDRESS_4,ADDRESS_5,DATE_CREATED,DATE_DELETED,ANCHOR_ID,SUPPLIER_IMAGE_BACKGROUND,SUPPLIER_LOGO_LARGE_SCALE_SMALLER) VALUES ('N','Y','SUP-0020','E&O Laboratories',null,null,'#00ADEA','<div class="syn_text-block">
  <div class="syn_visible-part">
			<h3 class="heavy-font">Clinical  Veterinary  Aquaculture  Pharmaceutical  Industrial  Cosmetic  Food, Water & Environmental</h3>
			<p class="heading-desc t-justify"><span class="main-color"><b>E&O Laboratories Ltd</b></span> is the UK’s largest, and leading, privately owned, manufacturer of Culture Media. E&O supply a comprehensive, high quality product range in various formats and in a wide range of volumes and containers to satisfy all the different business sector’s compliance criteria and laboratory requirements.</p>

</div>
	  <div class="syn_toggle-icon">
		<i class="fas fa-chevron-down"></i>
	  </div>
  <div class="syn_show-more-start">	
  
			<p class="heading-desc t-justify">E&O have two cGMP manufacturing sites to facilitate their fully automated production lines, steam sterilisation areas, validated clean-rooms and associated warehouse logistics function. Customer service, technical support, R&D, QC and QA are all sited at the main office in the Burnhouse facility.</p>

			<p class="heading-desc t-justify">All clinical products are CE marked, with industrial products being compliant with the Harmonized (USP/EP/JP) Pharmacopoeia standards.</p>

			<p class="heading-desc t-justify">Both sites are certified to ISO 9001:2015 & ISO 13485:2016 with quality control accredited by UKAS to EN ISO/IEC 17025:2017.</p>

   </div>
</div>',null,'Syntec Scientific','https://www.eolabs.com/','eo/eo-logo.png',null,'eo/eo-logo_400x267.jpg',null,null,null,null,null,null,null,null,'05-JAN-25',null,'_EO','assets/images/Backgrounds/Lab_16_opaque.png','width:80px;');
INSERT INTO syntec_suppliers_staging_v2 (DELETED,ACTIVE,SUPPLIER_ID,SUPPLIER_NAME,SHORT_NAME,CLASS_ID,CLASS_COLOUR,PROFILE_1,PROFILE_2,BUSINESS,WEBSITE,SUPPLIER_LOGO_LARGE,SUPPLIER_LOGO_SMALL,SUPPLIER_IMAGE_1,SUPPLIER_IMAGE_2,SUPPLIER_IMAGE_3,SUPPLIER_IMAGE_4,ADDRESS_1,ADDRESS_2,ADDRESS_3,ADDRESS_4,ADDRESS_5,DATE_CREATED,DATE_DELETED,ANCHOR_ID,SUPPLIER_IMAGE_BACKGROUND,SUPPLIER_LOGO_LARGE_SCALE_SMALLER) VALUES ('N','Y','SUP-0013','Alive Dx',null,null,'#02479C','<div class="syn_text-block">
  <div class="syn_visible-part">
				<div class="heading"><h3 class="heavy-font">At AliveDx, we know every minute matters for patients. That’s why we are fighting for faster disease detection and diagnosis.</h3></div>

				<p class="heading-desc t-justify">With over 30-years in in-vitro diagnostics, our mission is to empower diagnostic insights, transform patient care, and innovate for life. Here’s how our mission drives our actions:</p>
				<p class="heading-desc t-justify"><strong>We empower diagnostic insights</strong> by designing state-of-the-art easy-to-use solutions to optimize the work of laboratorians.</p>
				<p class="heading-desc t-justify"><strong>We transform patient care</strong> by shortening the time for disease detection and diagnosis, enabling patients to consider treatment options earlier.</p>
				<p class="heading-desc t-justify"><strong>We innovate for life</strong> by delivering innovative high-quality products, focusing on the health and wellness of patients and the day-to-day productivity and satisfaction of our clinical diagnostics partners.</p>
</div>
	  <div class="syn_toggle-icon">
		<i class="fas fa-chevron-down"></i>
	  </div>
	  
  <div class="syn_show-more-start">	
			<p class="heading-desc t-justify">We believe in the collective power of medicine. We are eager to partner with laboratorians and clinicians, patient advocacy groups, researchers, payers and industry partners to inspire innovation and build more valuable products. We are committed to creating clinical and economic value through these partnerships.</p>
			<p class="heading-desc t-justify">Today, our innovative products – Alba, our blood bank reagents portfolio, and MosaiQ, one of the first multiplexing and multimodality automated testing platforms – are revolutionizing clinical diagnostics worldwide. Our products are built with the patient in mind and are designed to make labs more efficient and clinical decision-making more effective.</p>
			<p class="heading-desc t-justify">Our Alba blood bank reagents portfolio enables patients in need of a transfusion to have access to a safe and timely blood match as we facilitate both patient and donor blood screening.</p>
			<p class="heading-desc t-justify">Our MosaiQ solution is designed to shorten time-to-diagnosis for patients by providing faster in-vitro test results. As an easy-to-use single solution, the platform performs multiple tests and gives maximum flexibility to laboratorians and clinicians.</p>
			<p class="heading-desc t-justify">We have evolved into AliveDx, starting our journey over 30 years ago. We became Alba Bioscience, and later, Quotient. As AliveDx, we continue to chart new pathways and innovate for life.</p>
			<p class="heading-desc t-justify">When we ‘feel alive,’ we do more than just live. Feeling alive is giving purpose, meaning and energy to our communities, our work and ourselves. We are AliveDx.</p>
   </div>
</div>',null,'Syntec Scientific','https://alivedx.com/','AliveDx/AliveDx-logo.png',null,'AliveDx/AliveDx-logo_400x267.jpg',null,null,null,null,null,null,null,null,'05-JAN-25',null,'_Alive','assets/images/Backgrounds/Lab_4_opaque.png','width:70px;');
