</div>',null,'Syntec Scientific','https://www.axlab.dk/en/','AxLab/AxLab-logo.png',null,'AxLab/AxLab-logo_400x267.jpg',null,null,null,null,null,null,null,null,'05-JAN-25',null,'_AxLab','assets/images/Backgrounds/Lab_7_opaque.png','width:70px;');
INSERT INTO syntec_suppliers_staging_v2 (DELETED,ACTIVE,SUPPLIER_ID,SUPPLIER_NAME,SHORT_NAME,CLASS_ID,CLASS_COLOUR,PROFILE_1,PROFILE_2,BUSINESS,WEBSITE,SUPPLIER_LOGO_LARGE,SUPPLIER_LOGO_SMALL,SUPPLIER_IMAGE_1,SUPPLIER_IMAGE_2,SUPPLIER_IMAGE_3,SUPPLIER_IMAGE_4,ADDRESS_1,ADDRESS_2,ADDRESS_3,ADDRESS_4,ADDRESS_5,DATE_CREATED,DATE_DELETED,ANCHOR_ID,SUPPLIER_IMAGE_BACKGROUND,SUPPLIER_LOGO_LARGE_SCALE_SMALLER) VALUES ('N','Y','SUP-0027','Co-Dx',null,null,'#ad2226','<p class="heading-desc t-justify"><span class="main-color"><b>Co-Dx (Co-Diagnostics, Inc.)</b></span> is a molecular diagnostics company pioneering accessible, high-performance PCR testing through its patented Co-Primers™ technology. Headquartered in Salt Lake City, Utah, Co-Dx develops and manufactures diagnostic solutions for a broad spectrum of infectious diseases, including COVID-19, tuberculosis, HPV, Zika virus, and more. Its mission is to improve global health by delivering reliable and affordable diagnostics that empower decentralized testing—bringing lab-quality results to clinics, care facilities, and even remote or resource-limited settings.
</p>

<p class="heading-desc t-justify">At the core of Co-Dx’s innovation is the <b>Co-Dx PCR Pro™ Platform></b>—a portable, real-time PCR device designed for point-of-care use. It pairs with mobile devices via Bluetooth and supports multiplex testing with gold-standard accuracy, eliminating the delays and logistics of traditional centralized lab workflows. Co-Dx also offers a growing menu of Logix Smart® test kits built to work seamlessly with this platform. By combining precision molecular diagnostics with mobility and simplicity, Co-Dx is helping reshape how and where critical health decisions are made.</p>',null,'Syntec Scientific','https://co-dx.com/our-story/','co-diagnostics/co-diagnostics-logo.png',null,'co-diagnostics/co-diagnostics-logo_400x267.jpg',null,null,null,null,null,null,null,null,'05-JAN-25',null,'_CoDiagnostics','assets/images/Backgrounds/Lab_48_opaque.png','width:100px;');
INSERT INTO syntec_suppliers_staging_v2 (DELETED,ACTIVE,SUPPLIER_ID,SUPPLIER_NAME,SHORT_NAME,CLASS_ID,CLASS_COLOUR,PROFILE_1,PROFILE_2,BUSINESS,WEBSITE,SUPPLIER_LOGO_LARGE,SUPPLIER_LOGO_SMALL,SUPPLIER_IMAGE_1,SUPPLIER_IMAGE_2,SUPPLIER_IMAGE_3,SUPPLIER_IMAGE_4,ADDRESS_1,ADDRESS_2,ADDRESS_3,ADDRESS_4,ADDRESS_5,DATE_CREATED,DATE_DELETED,ANCHOR_ID,SUPPLIER_IMAGE_BACKGROUND,SUPPLIER_LOGO_LARGE_SCALE_SMALLER) VALUES ('N','Y','SUP-0029','Infrico',null,null,'#F5C641','<p class="heading-desc t-justify"><span class="main-color"><b>INFRICO</b></span> was born in 1986 with a clear objective: to generate the best cooling solutions adapted to the specific needs of each client.
					</p>

					<p class="heading-desc t-justify">At Infrico, we want to contribute to the progress of society and we do it as best we know, by applying the latest technology in R & D & manufacturing equipment industrial cold that offer solutions ensuring the well–being and ensuring health and aliment safety and also medical and pharmaceutical safety.
					</p>

					<p class="heading-desc t-justify">Thanks to our knowledge, all Infrico cold equipment certify the conservation and therefore the optimal organoleptic conditions of the food. Freshness and maximum flavor guaranteed. The same know-how transferred to our line Infrico Medcare, ensures the perfect preservation of biological samples with high added value.
					</p>',null,null,'Infrico/Infrico-logo.png','trimero/trimero-logo.png',null,'Infrico/Infrico-logo_400x267.jpg',null,null,null,null,null,null,null,null,'25-FEB-25',null,'_Infrico',null,'width:90px;');
INSERT INTO syntec_suppliers_staging_v2 (DELETED,ACTIVE,SUPPLIER_ID,SUPPLIER_NAME,SHORT_NAME,CLASS_ID,CLASS_COLOUR,PROFILE_1,PROFILE_2,BUSINESS,WEBSITE,SUPPLIER_LOGO_LARGE,SUPPLIER_LOGO_SMALL,SUPPLIER_IMAGE_1,SUPPLIER_IMAGE_2,SUPPLIER_IMAGE_3,SUPPLIER_IMAGE_4,ADDRESS_1,ADDRESS_2,ADDRESS_3,ADDRESS_4,ADDRESS_5,DATE_CREATED,DATE_DELETED,ANCHOR_ID,SUPPLIER_IMAGE_BACKGROUND,SUPPLIER_LOGO_LARGE_SCALE_SMALLER) VALUES ('N','Y','SUP-0012','Aesku Diagnostics',null,null,'#F5A300','<div class="syn_text-block">
  <div class="syn_visible-part">
				<p class="heading-desc t-justify">
				<b>AESKU.GROUP, based in Wendelsheim, Germany, is a research-focused supplier of innovative and efficient products and services for the early detection, diagnosis and prognosis of autoimmune diseases.</b></p>

				<p class="heading-desc t-justify">
				In only ten years since its foundation in the year 2000 AESKU.DIAGNOSTICS has become a recognized name in the field of autoimmunity for launching over 150 different products together with uninterrupted services in more than 90 countries worldwide.</p>
</div>
	  <div class="syn_toggle-icon">
		<i class="fas fa-chevron-down"></i>
	  </div>
	  
	  
  <div class="syn_show-more-start">		  
<p class="heading-desc t-justify">
Since then AESKU.Group simplifies the lab routine with accurate, robust and reliable tests, laying equal emphasis on all major disease sectors, the company has earned a solid reputation in autoimmune diagnostics.</p>

<p class="heading-desc t-justify">
Nowadays the AESKU.GROUP is a group of companies that includes AESKU.DIAGNOSTICS (Autoimmunity IVD), AESKU.THERAPY (Autoimmune Therapies), AESKU.SYSTEMS (Lab Automation), AESKU.KIPP INSTITUTE (International Research Cooperation) and the subsidiaries AESKU.INC (US).</p>

<p class="heading-desc t-justify">
As of 03.01.2023, AESKU.SYSTEMS will no longer act as the legal manufacturer of Lab Automation products. From this date on, the legal manufacturer will be AESKU.DIAGNOSTICS.</p>

<p class="heading-desc t-justify">
Besides its own outstanding commitment to research and development AESKU.DIAGNOSTICS has initiated and supports the AESKU.KIPP INSTITUTE, a non-profit organization, primarily active in basic research and interdiciplinary knowledge transfer in autoimmunity.</p>

<p class="heading-desc t-justify">
AESKU.GROUP is distinguished by the extraordinary synthesis of networked scientific competence and clear orientation to practical issues, providing ideal conditions for the timely implementation of current research into new diagnostic and therapeutic options.</p>
<p class="heading-desc t-justify">
The mission of AESKU.GROUP is based on fundamental values that define our way how we do business and how we work together with our customers, partners and our own employees.</p>
  </div>
</div>',null,'Syntec Scientific','https://www.aesku.com/index.php/diagnostics','aesku/aesku-logo.png',null,'aesku/aesku-logo_400x267.jpg',null,null,null,null,null,null,null,null,'05-JAN-25',null,'_Aesku','assets/images/Backgrounds/Lab_3_opaque.png','width:110px;');
INSERT INTO syntec_suppliers_staging_v2 (DELETED,ACTIVE,SUPPLIER_ID,SUPPLIER_NAME,SHORT_NAME,CLASS_ID,CLASS_COLOUR,PROFILE_1,PROFILE_2,BUSINESS,WEBSITE,SUPPLIER_LOGO_LARGE,SUPPLIER_LOGO_SMALL,SUPPLIER_IMAGE_1,SUPPLIER_IMAGE_2,SUPPLIER_IMAGE_3,SUPPLIER_IMAGE_4,ADDRESS_1,ADDRESS_2,ADDRESS_3,ADDRESS_4,ADDRESS_5,DATE_CREATED,DATE_DELETED,ANCHOR_ID,SUPPLIER_IMAGE_BACKGROUND,SUPPLIER_LOGO_LARGE_SCALE_SMALLER) VALUES ('N','Y','SUP-0030','Merck Group',null,null,'#503191','<div class="syn_text-block">
  <div class="syn_visible-part">
				<p class="heading-desc t-justify"><span class="main-color"><b>Merck Group</b></span>  (also known as Merck KGaA) is a leading global science and technology company specializing in Healthcare, Life Science, and Electronics. Founded in 1668 in Darmstadt, Germany, Merck is one of the oldest pharmaceutical and chemical companies in the world..</p>
</div>
	  <div class="syn_toggle-icon">
		<i class="fas fa-chevron-down"></i>
	  </div>
  <div class="syn_show-more-start">		  
					<p class="heading-desc t-justify"><b>Business Sectors</b></p>

					<ul class="ullist">
					<li><span class="heading-desc t-justify"><b>Healthcare:</b> Prescription medicines, oncology, neurology, immunology, fertility treatments</span></li>
					<li><span class="heading-desc t-justify"><b>Life Science:</b> Lab materials, biotech, diagnostic tools, research solutions</span></li>
					<li><span class="heading-desc t-justify"><b>Electronics:</b> Semiconductor materials, display technologies, specialty chemicals</span><br><br></li>
					</ul>

					<p class="heading-desc t-justify"><b>Innovation & Sustainability</b></p>
					<p class="heading-desc t-justify">Merck Group invests heavily in R&D, pioneering advances in biotechnology, pharmaceuticals, and digital healthcare. The company is committed to sustainability, with goals to become climate neutral by 2040.</p>
   </div>
</div>',null,null,'https://www.merckgroup.com/en','Merck/Merck-logo.png',null,'Merck/Merck-logo_400x267.jpg',null,null,null,null,null,null,null,null,'24-MAR-25',null,'_merck','assets/images/Scientific/suppliers/Milestone/Background_opaque.png','width:90px;');
