INSERT INTO syntec_suppliers_staging_v2 (DELETED,ACTIVE,SUPPLIER_ID,SUPPLIER_NAME,SHORT_NAME,CLASS_ID,CLASS_COLOUR,PROFILE_1,PROFILE_2,BUSINESS,WEBSITE,SUPPLIER_LOGO_LARGE,SUPPLIER_LOGO_SMALL,SUPPLIER_IMAGE_1,SUPPLIER_IMAGE_2,SUPPLIER_IMAGE_3,SUPPLIER_IMAGE_4,ADDRESS_1,ADDRESS_2,ADDRESS_3,ADDRESS_4,ADDRESS_5,DATE_CREATED,DATE_DELETED,ANCHOR_ID,SUPPLIER_IMAGE_BACKGROUND,SUPPLIER_LOGO_LARGE_SCALE_SMALLER) VALUES ('N','Y','SUP-0003','Cell Marque',null,null,'#EC432E','<div class="syn_text-block">
  <div class="syn_visible-part">
					<p class="heading-desc t-justify">
					<span class="main-color"><b>Cell Marque Corporation</b></span>
					 manufactures and supplies primary antibodies to ventana medical systems. The Company offers buffers and pretreatment, chromogens, ancillary reagents, and lab equipments. Cell Marque serves customers worldwide.</p>

</div>
	  <div class="syn_toggle-icon">
		<i class="fas fa-chevron-down"></i>
	  </div>
	  
  <div class="syn_show-more-start">		  
						<p class="heading-desc t-justify">
						Founded in 1994, Cell Marque has 25 years of experience in the production of antibodies for clinical pathology. The Cell Marque antibody product line offers an abundant portfolio of primary antibodies suitable for diagnostic use in immunohistochemistry (IHC), on formalin-fixed, paraffin-embedded tissue samples. Their in vitro diagnostic (IVD) range includes novel antibodies, detection systems, and advanced ancillary reagents for clinical testing in the histopathology laboratory. With a medical team on staff, Cell Marque’s development strategy means maintaining relentless dedication to the latest clinical needs to further serve the market, and to supply you with the best care for your patients.
						</p>

						<p class="heading-desc t-justify">
						Cell Marque’s reputation as a provider of high quality, fit-for-purpose IHC antibodies and reagents was further enhanced following its acquisition by Sigma-Aldrich in 2014. Now part of MilliporeSigma, the US life science business of Merck KGaA based in Darmstadt, Germany; Cell Marque’s products and scientific expertise complement Sigma-Aldrich’s workflow solutions aimed at IVD customers.
						</p>

						<p class="heading-desc t-justify">
						To assist with product selection, primary antibodies are organised according to histopathology speciality. Within their extensive portfolio can be found monoclonal and polyclonal antibodies for use in anatomic pathology, breast & gynaecological pathology, cytopathology, dermatopathology, gastrointestinal (GI) pathology, genitourinary (GU) pathology, head and neck pathology, hematopathology, neuropathology, paediatric pathology, pulmonary pathology and soft tissue pathology. Additionally, Cell Marque’s IHC product portfolio also includes substrates and detection systems, control slides, blocking buffers and diluents.</p>
						</p>


						<div class="center-text" style="display: flex; flex-direction: column; align-items: center;">
						<img class="fx animated fadeInLeft" data-animate="fadeInLeft" alt="" src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/Millipore.png" style="margin-bottom:30px; ">
						 </div>
 
   </div>
</div>',null,'Syntec Scientific','https://www.cellmarque.com/cms/index.php','Cell_Marque/cell_marque-logo.png',null,'Cell_Marque/cell_marque-logo_400x267.jpg',null,null,null,null,null,null,null,null,'05-JAN-25',null,'_CellMarque','assets/images/Backgrounds/Lab_14_opaque.png','width:80px;');
INSERT INTO syntec_suppliers_staging_v2 (DELETED,ACTIVE,SUPPLIER_ID,SUPPLIER_NAME,SHORT_NAME,CLASS_ID,CLASS_COLOUR,PROFILE_1,PROFILE_2,BUSINESS,WEBSITE,SUPPLIER_LOGO_LARGE,SUPPLIER_LOGO_SMALL,SUPPLIER_IMAGE_1,SUPPLIER_IMAGE_2,SUPPLIER_IMAGE_3,SUPPLIER_IMAGE_4,ADDRESS_1,ADDRESS_2,ADDRESS_3,ADDRESS_4,ADDRESS_5,DATE_CREATED,DATE_DELETED,ANCHOR_ID,SUPPLIER_IMAGE_BACKGROUND,SUPPLIER_LOGO_LARGE_SCALE_SMALLER) VALUES ('N','Y','SUP-0007','Milestone',null,null,'#E7422A','<div class="syn_text-block">
		<div class="syn_visible-part">
								<p class="heading-desc t-justify">
								Our mission is to reduce patient anxiety by providing pathologists with technologies for same-day diagnostic results.</p>

								<p class="heading-desc t-justify">
								Today, Milestone is proud to offer innovative solutions in six different fields: Frozen Section, Cytology, Sample Handling, Tissue Processing, Macro Digital and Reagents. All products aim to help patients and to create a better laboratory environment for the medical staff of both the Anatomical Pathology and Surgical Rooms.
								</p>
		</div>	
		
			  <div class="syn_toggle-icon">
				<i class="fas fa-chevron-down"></i>
			  </div>
  
		 <div class="syn_show-more-start">
								<p class="heading-desc t-justify">
								Milestone’s skilled group of professionals study every new project, from the drawings to the final prototype, getting to the final stage in which the operating units are ready for the labs.
								<br>


								<br>Milestone is a company headquartered in Bergamo/Northern Italy. It was founded in 1988 as a company specializing in advanced microwave instrumentation for sample preparation in analytical and organic chemistry laboratories. By DNA, Milestone is a pre-analytical, sample preparation company – understanding the paramount and crucial importance of the pre-analytical step for any analysis further downstream.<br>
								<br>In 1994, Milestone established a separate Medical Division to expand our expertise to the world of histopathology. Driven by the conviction that “we need to do better” when dealing with human specimen – and our mission: Helping Patients. Today, our instruments are used in the most renowned clinical and research laboratories around the world with an installed base of 15,000 in 93 countries. We continue to lead the industry with constant innovation and improvements to obtain full chain-of-custody of patients’ specimen, thus providing the optimal basis for an accurate diagnosis. <b>We leave nothing to chance.</b>

								</p>
			</div>		
			
					
								
								
</div>',null,'Syntec Scientific','https://www.milestonemedsrl.com/','Milestone/milestone-medical-logo.png',null,'Milestone/milestone-logo_400x267.jpg',null,null,null,null,null,null,null,null,'05-JAN-25',null,'_Milestone','assets/images/Scientific/suppliers/Milestone/Background_opaque.png','width:100px;');
