INSERT INTO syntec_suppliers_staging_v2 (DELETED,ACTIVE,SUPPLIER_ID,SUPPLIER_NAME,SHORT_NAME,CLASS_ID,CLASS_COLOUR,PROFILE_1,PROFILE_2,BUSINESS,WEBSITE,SUPPLIER_LOGO_LARGE,SUPPLIER_LOGO_SMALL,SUPPLIER_IMAGE_1,SUPPLIER_IMAGE_2,SUPPLIER_IMAGE_3,SUPPLIER_IMAGE_4,ADDRESS_1,ADDRESS_2,ADDRESS_3,ADDRESS_4,ADDRESS_5,DATE_CREATED,DATE_DELETED,ANCHOR_ID,SUPPLIER_IMAGE_BACKGROUND,SUPPLIER_LOGO_LARGE_SCALE_SMALLER) VALUES ('N','N','SUP-0036','Vazyme Biotech',null,null,'#014099','<p class="heading-desc t-justify"><span class="main-color"><b>Vazyme Biotech Co., Ltd.</b></span> is a global life-science technology company founded in 2012 and headquartered in Nanjing, China. 
The company specialises in the design, manufacture and application of advanced reagents, enzymes and molecular biology solutions, including PCR and qPCR kits, NGS library preparation reagents, RNA/DNA extraction kits, proteins and antibodies. 
 With a presence in over 60 countries and a manufacturing infrastructure built around in-house production and GMP-grade quality systems, Vazyme serves academic, diagnostic, industrial and biotech customers worldwide.</p>

<p class="heading-desc t-justify">Driven by the mission “Science and Technology Make a Healthier Life”, Vazyme has built more than 1,000 genetically engineered enzymes, over 3,000 high-performance materials and thousands of product SKUs to support emerging life-science workflows. 
The company emphasises innovation and speed to market, with technologies spanning synthetic biology, high-throughput automation and next-generation sequencing solutions—enabling customers to move from sample to insight with fewer bottlenecks</p>',null,'Syntec Scientific','https://www.vazymeglobal.com/','Vazyme/vazyme_logo.png',null,'Vazyme/vazyme-logo_400x267.png',null,null,null,null,null,null,null,null,'11-MAY-25',null,'_Vazyme','assets/images/images_misc/Lab_96_opaque.png','width:100px;');
