INSERT INTO syntec_suppliers_staging_v2 (DELETED,ACTIVE,SUPPLIER_ID,SUPPLIER_NAME,SHORT_NAME,CLASS_ID,CLASS_COLOUR,PROFILE_1,PROFILE_2,BUSINESS,WEBSITE,SUPPLIER_LOGO_LARGE,SUPPLIER_LOGO_SMALL,SUPPLIER_IMAGE_1,SUPPLIER_IMAGE_2,SUPPLIER_IMAGE_3,SUPPLIER_IMAGE_4,ADDRESS_1,ADDRESS_2,ADDRESS_3,ADDRESS_4,ADDRESS_5,DATE_CREATED,DATE_DELETED,ANCHOR_ID,SUPPLIER_IMAGE_BACKGROUND,SUPPLIER_LOGO_LARGE_SCALE_SMALLER) VALUES ('N','Y','SUP-0010','SLEE',null,null,'#004684','<div class="syn_text-block">
  <div class="syn_visible-part">
    <p class="heading-desc t-justify">
      <strong>Providing the best histopathology solutions is our passion, our know-how and our craft.</strong>
    </p>
    <p class="heading-desc t-justify">
      We stand for top technology, high quality standards and consistent customer support. From the invention of the world´s first cryostat back in 1954 by our company founder Kenneth Slee until today, we focus on improving the microscopic sample preparation process. The everyday needs of our global users are top priority to us.
    </p>
  </div>

  <div class="syn_toggle-icon">
    <i class="fas fa-chevron-down"></i>
  </div>

  <div class="syn_show-more-start">
    <p class="heading-desc t-justify">
      Our headquarters with design center and product manufacturing is located in the RhineMain area for decades. A location in the center of Germany with highest expertise in science, research and high-tech manufacturing to get benefited from the German tradition in top quality and high-precision products.
    </p>
  </div>
</div>',null,'Syntec Scientific','https://www.slee.de/','slee/slee-logo.png',null,'slee/slee-logo_400x267.jpg',null,null,null,null,null,null,null,null,'05-JAN-25',null,'_SLEE','assets/images/Scientific/suppliers/slee/Background_opaque.png','width:70px;');
INSERT INTO syntec_suppliers_staging_v2 (DELETED,ACTIVE,SUPPLIER_ID,SUPPLIER_NAME,SHORT_NAME,CLASS_ID,CLASS_COLOUR,PROFILE_1,PROFILE_2,BUSINESS,WEBSITE,SUPPLIER_LOGO_LARGE,SUPPLIER_LOGO_SMALL,SUPPLIER_IMAGE_1,SUPPLIER_IMAGE_2,SUPPLIER_IMAGE_3,SUPPLIER_IMAGE_4,ADDRESS_1,ADDRESS_2,ADDRESS_3,ADDRESS_4,ADDRESS_5,DATE_CREATED,DATE_DELETED,ANCHOR_ID,SUPPLIER_IMAGE_BACKGROUND,SUPPLIER_LOGO_LARGE_SCALE_SMALLER) VALUES ('N','Y','SUP-0019','Dagatron',null,null,'#00A4E1','<div class="syn_text-block">
  <div class="syn_visible-part">
<p class="heading-desc t-justify">
      <span class="main-color"><b>DAGATRONICS CORPORATION</b></span>, founded in 1994 in South Korea,
      has been dedicated to advancing the standards of clinical laboratory equipment through
      innovation and excellence in the field of In-vitro Diagnostic (IVD) technology.
</p>
<p class="heading-desc t-justify">
      Our brand, <b>DAGATRON</b>, is renowned for its cutting-edge Automated Slide Stainers,
      which are pivotal in microbiology, hematology, and cytology applications. These advanced systems are engineered
      to deliver precise GRAM and AFB staining, crucial for accurate diagnostic results in microbiology.
      In hematology and cytology, our stainers are designed to provide comprehensive analysis with high performance,
      ensuring reliable assessments of blood and cellular samples.
</p>
</div>
	  <div class="syn_toggle-icon">
		<i class="fas fa-chevron-down"></i>
	  </div>
  <div class="syn_show-more-start">		
  
<p class="heading-desc t-justify">
      At <b>DAGATRONICS</b>, we prioritize innovation and user-centric design.
      Our staining systems are crafted to offer exceptional performance while emphasizing ease of use
      and operational simplicity. This approach not only enhances the efficiency of laboratory workflows but also
      ensures that complex staining processes are streamlined and accessible.
</p>
<p class="heading-desc t-justify">
      Over the past two decades, <b>DAGATRONICS</b> has forged strong global partnerships,
      extending our reach and influence in the IVD industry. Our products are trusted and widely adopted by leading
      hospital laboratories and public health centers worldwide. This widespread endorsement reflects our commitment
      to delivering high-quality solutions that meet the rigorous demands of modern diagnostic practices.
</p>
<p class="heading-desc t-justify">
      As we continue to push the boundaries of IVD technology, our mission remains focused on providing innovative,
      reliable, and efficient tools that support the advancement of healthcare. We are dedicated to maintaining the
      highest standards of accuracy and performance in all our products, reinforcing our role as a 
      pioneering force in the diagnostic field.
    </p>
   </div>
</div>',null,'Syntec Scientific','http://www.dagatron.com/en/','dagatron/dagatron-logo.png',null,'dagatron/dagatronìcs-logo_400x267.jpg',null,null,null,null,null,null,null,null,'05-JAN-25',null,'_Dagatron','assets/images/Backgrounds/Lab_13_opaque.png','width:80px;');
INSERT INTO syntec_suppliers_staging_v2 (DELETED,ACTIVE,SUPPLIER_ID,SUPPLIER_NAME,SHORT_NAME,CLASS_ID,CLASS_COLOUR,PROFILE_1,PROFILE_2,BUSINESS,WEBSITE,SUPPLIER_LOGO_LARGE,SUPPLIER_LOGO_SMALL,SUPPLIER_IMAGE_1,SUPPLIER_IMAGE_2,SUPPLIER_IMAGE_3,SUPPLIER_IMAGE_4,ADDRESS_1,ADDRESS_2,ADDRESS_3,ADDRESS_4,ADDRESS_5,DATE_CREATED,DATE_DELETED,ANCHOR_ID,SUPPLIER_IMAGE_BACKGROUND,SUPPLIER_LOGO_LARGE_SCALE_SMALLER) VALUES ('N','Y','SUP-0022','EKF Diagnostics',null,null,'#F68920','<h3 class="heavy-font">EKF Diagnostics is a medical device manufacturer</h3>


<p class="heading-desc t-justify"><span class="main-color"><b>EKF Diagnostics</b></span>  is a global medical diagnostics company specializing in point-of-care testing and central laboratory instruments. Headquartered in the UK, it provides a broad portfolio of analyzers and tests, including hemoglobin, glucose, lactate, HbA1c, and beta-hydroxybutyrate, serving both clinical and research markets. Its products are trusted worldwide for their accuracy, reliability, and ease of use, with distribution in over 120 countries. EKF also offers connectivity solutions that integrate seamlessly into healthcare systems, ensuring efficient data management and improved patient care.</p>
	
<p class="heading-desc t-justify">Beyond diagnostics, EKF has built a strong life sciences division focused on enzyme production and contract manufacturing. Operating FDA-registered, cGMP-compliant facilities in the U.S., the company supplies high-quality reagents and raw materials used in diagnostic assays and other biotech applications. This dual focus—on both finished diagnostics and life science components—positions EKF as a flexible, innovative partner in the global healthcare and laboratory sectors.</p>',null,'Syntec Scientific','https://www.ekfusa.com/','EKF/EKF-logo.png',null,'EKF/EKF-logo_400x267.jpg',null,null,null,null,null,null,null,null,'05-JAN-25',null,'_EKF','assets/images/Backgrounds/Lab_17_opaque.png','width:70px;');
INSERT INTO syntec_suppliers_staging_v2 (DELETED,ACTIVE,SUPPLIER_ID,SUPPLIER_NAME,SHORT_NAME,CLASS_ID,CLASS_COLOUR,PROFILE_1,PROFILE_2,BUSINESS,WEBSITE,SUPPLIER_LOGO_LARGE,SUPPLIER_LOGO_SMALL,SUPPLIER_IMAGE_1,SUPPLIER_IMAGE_2,SUPPLIER_IMAGE_3,SUPPLIER_IMAGE_4,ADDRESS_1,ADDRESS_2,ADDRESS_3,ADDRESS_4,ADDRESS_5,DATE_CREATED,DATE_DELETED,ANCHOR_ID,SUPPLIER_IMAGE_BACKGROUND,SUPPLIER_LOGO_LARGE_SCALE_SMALLER) VALUES ('N','Y','SUP-0023','MMQCI',null,null,'#FFCB0D','<p class="heading-desc t-justify"><span class="main-color"><b>Maine Molecular Quality Controls, Inc. (MMQCI)</b></span> designs and markets molecular controls for use in inherited disease testing and infectious disease detection.</p>

<p class="heading-desc t-justify">As experts in quality assurance of laboratory medicine, MMQCI produces high caliber controls uniquely suited to monitor all phases of molecular testing as required by best practice and regulations. MMQCI controls provide confidence in test results.</p>

<p class="heading-desc t-justify">MMQCI continues to design and produce innovative, high-quality control products as needed for emerging nucleic acid technologies as they come into use by the molecular diagnostic community. Custom orders from in vitro diagnostic manufacturers are always welcome at MMQCI''s cGMP facility.</p>',null,'Syntec Scientific','https://www.mmqci.com/','mmqci/mmqci-logo.png',null,'mmqci/mmqci-logo_400x267.jpg',null,null,null,null,null,null,null,null,'05-JAN-25',null,'_MMQCI','assets/images/Backgrounds/Lab_6_opaque.png','width:80px;');
INSERT INTO syntec_suppliers_staging_v2 (DELETED,ACTIVE,SUPPLIER_ID,SUPPLIER_NAME,SHORT_NAME,CLASS_ID,CLASS_COLOUR,PROFILE_1,PROFILE_2,BUSINESS,WEBSITE,SUPPLIER_LOGO_LARGE,SUPPLIER_LOGO_SMALL,SUPPLIER_IMAGE_1,SUPPLIER_IMAGE_2,SUPPLIER_IMAGE_3,SUPPLIER_IMAGE_4,ADDRESS_1,ADDRESS_2,ADDRESS_3,ADDRESS_4,ADDRESS_5,DATE_CREATED,DATE_DELETED,ANCHOR_ID,SUPPLIER_IMAGE_BACKGROUND,SUPPLIER_LOGO_LARGE_SCALE_SMALLER) VALUES ('N','Y','SUP-0016','Alveo',null,null,'#4AAFBE','<p class="heading-desc t-justify"><span class="main-color"><b>Alveo Technologies Inc.</b></span> provides diagnostic imaging services. The Company focuses on applying cutting edge advances in sensing, microfluidics, and bioassays for disease and personal care diagnostic devices. </p>


 <p class="heading-desc t-justify">We make molecular detection and diagnostics universally accessible – on the farm, in the field, in the clinic, or in the manufacturing plant – helping prevent or significantly limit the destructive impact of viruses, fungi, bacteria, and other pathogens by detecting earlier at the Point of Need™.</p>',null,'Syntec Scientific','https://www.alveotechnologies.com/','Alveo/Alveo-logo.png',null,'Alveo/Alveo-logo_400x267.jpg',null,null,null,null,null,null,null,null,'05-JAN-25',null,'_Alveo','assets/images/Backgrounds/Lab_5_opaque.png','width:80px;');
INSERT INTO syntec_suppliers_staging_v2 (DELETED,ACTIVE,SUPPLIER_ID,SUPPLIER_NAME,SHORT_NAME,CLASS_ID,CLASS_COLOUR,PROFILE_1,PROFILE_2,BUSINESS,WEBSITE,SUPPLIER_LOGO_LARGE,SUPPLIER_LOGO_SMALL,SUPPLIER_IMAGE_1,SUPPLIER_IMAGE_2,SUPPLIER_IMAGE_3,SUPPLIER_IMAGE_4,ADDRESS_1,ADDRESS_2,ADDRESS_3,ADDRESS_4,ADDRESS_5,DATE_CREATED,DATE_DELETED,ANCHOR_ID,SUPPLIER_IMAGE_BACKGROUND,SUPPLIER_LOGO_LARGE_SCALE_SMALLER) VALUES ('N','Y','SUP-0025','RatioLab',null,null,'#E73331','<div class="syn_text-block">
  <div class="syn_visible-part">
<p class="heading-desc t-justify">As a leading international manufacturer of laboratory consumables we have been supplying laboratory dealers in Germany and abroad as well as domestic end customers from industry, research and medicine with high-quality and innovative laboratory consumables made of plastics for almost 50 years. Our Think! team will work with you on developing customized product solutions for laboratories and closely align with you throughout the whole process from development to serial production.
</p>
</div>
	  <div class="syn_toggle-icon">
		<i class="fas fa-chevron-down"></i>
	  </div>
  <div class="syn_show-more-start">

<p class="heading-desc t-justify">Almost all single use products are manufactured at our production facility in Szada/Hungary. Every day, tens of thousands of laboratory articles are produced on state-of-the-art injection moulding machines using high quality plastics and tools with utmost precision. Upon request, we develop customized packagings, in large or small quantaties, assembled based on your cleanliness requirements.
</p>
   </div>
</div>',null,'Syntec Scientific','https://www.ratiolab.com/en/','ratiolab/ratiolab-logo.png',null,'ratiolab/ratiolab-logo_400x267.jpg',null,null,null,null,null,null,null,null,'05-JAN-25',null,'_RatioLab','assets/images/Scientific/suppliers/ratiolab/ratiolab_background_1.png','width:70px;');
INSERT INTO syntec_suppliers_staging_v2 (DELETED,ACTIVE,SUPPLIER_ID,SUPPLIER_NAME,SHORT_NAME,CLASS_ID,CLASS_COLOUR,PROFILE_1,PROFILE_2,BUSINESS,WEBSITE,SUPPLIER_LOGO_LARGE,SUPPLIER_LOGO_SMALL,SUPPLIER_IMAGE_1,SUPPLIER_IMAGE_2,SUPPLIER_IMAGE_3,SUPPLIER_IMAGE_4,ADDRESS_1,ADDRESS_2,ADDRESS_3,ADDRESS_4,ADDRESS_5,DATE_CREATED,DATE_DELETED,ANCHOR_ID,SUPPLIER_IMAGE_BACKGROUND,SUPPLIER_LOGO_LARGE_SCALE_SMALLER) VALUES ('N','Y','SUP-0021','Erlab',null,null,'#00C0F3','<h3 class="heavy-font">Environmentally sustainable air filtration solution for the protection of lab personnel (Collective Personel Equipment)</h3>
	
	




<p class="heading-desc t-justify">Inventor of ductless fume hood, Erlab is an expert in air filtration for the protection of laboratory personnel since 1968. With over 50 years of experience, 150,000 units of installed base in 40 countries, Erlab offers advanced technologies that protect life, save money and enhances environment sustainability. All our products our certified by our experts for individual applications ensuring that our products fully meet customer expectations.</p>

<p class="heading-desc t-justify">With manufacturing facilities, in US, China, Europe and highly trained engineers and scientists worldwide, we deliver solutions globally.</p>

<p class="heading-desc t-justify">We continue to protect health in wide range of laboratories including Higher Education, Chemicals Labs, Pharmaceuticals, Biotechnology, Petrochem, Industrial and Food & Beverages etc. </p>',null,'Syntec Scientific','https://www.erlab.com/en/','erlab/erlab-logo.png',null,'erlab/erlab-logo_400x267.jpg',null,null,null,null,null,null,null,null,'05-JAN-25',null,'_Erlab','assets/images/Backgrounds/Lab_18_opaque.png','width:80px;');
INSERT INTO syntec_suppliers_staging_v2 (DELETED,ACTIVE,SUPPLIER_ID,SUPPLIER_NAME,SHORT_NAME,CLASS_ID,CLASS_COLOUR,PROFILE_1,PROFILE_2,BUSINESS,WEBSITE,SUPPLIER_LOGO_LARGE,SUPPLIER_LOGO_SMALL,SUPPLIER_IMAGE_1,SUPPLIER_IMAGE_2,SUPPLIER_IMAGE_3,SUPPLIER_IMAGE_4,ADDRESS_1,ADDRESS_2,ADDRESS_3,ADDRESS_4,ADDRESS_5,DATE_CREATED,DATE_DELETED,ANCHOR_ID,SUPPLIER_IMAGE_BACKGROUND,SUPPLIER_LOGO_LARGE_SCALE_SMALLER) VALUES ('N','Y','SUP-0024','Munro Instruments',null,null,'#FF0000','<p class="heading-desc t-justify"><span class="main-color"><b>Munro Instruments</b></span> manufactures specialist scientific equipment and instrumentation. Founded in 1864 the company is recognised worldwide for its innovative spirit and exceptional versatility.</p>

<p class="heading-desc t-justify"><b>We currently operate across three core product lines:</b></p>

<ul class="ullist">
<li><span class="heading-desc t-justify">Meteorology – Professional-grade equipment to monitor the wind, rainfall, temperature and humidity.</span><br></li>
<li><span class="heading-desc t-justify">Air Quality – Portable Air Samplers for workplace air quality assessments</span><br></li>
<li><span class="heading-desc t-justify">Slip & Skid Resistance – Pendulum Testers to evaluate the slip/skid risk of pedestrian surfaces and roads.</span><br></li>
</ul>


<p class="heading-desc t-justify">We supply to organisations worldwide, including meteorological offices, airports, defence ministries, power stations and offshore rigs. Our Pendulum Tester is used by many of the world’s leading tile and flooring manufacturers, tyre companies, highway authorities, forensic engineers and health-and-safety consultants.</p>

<p class="heading-desc t-justify">To this day Munro Instruments remains a bastion of high-quality British manufacturing. Our history is strongly rooted in the London and Essex area, having occupied various premises in Lambeth, Clerkenwell, Kings Cross, Tottenham, Bounds Green, Barking and Redbridge. Our factory and offices are currently located in Harlow.</p>

<p class="heading-desc t-justify">In 2019 Munro Instruments became part of the MRC group of companies. We now offer an extensive range of laboratory Equipment. Visit our dedicated laboratory website for more information.</p>

<p class="heading-desc t-justify">We have also joined forces with Grip Potential, a leading slip risk consultancy. Visit the Grip Potential website for information on the range of services on offer.</p>',null,'Syntec Scientific','https://www.munroinstruments.com/','munro/munro-logo.png',null,'munro/munro-logo_400x267.jpg',null,null,null,null,null,null,null,null,'05-JAN-25',null,'_Munro','assets/images/Backgrounds/Lab_10_opaque.png','width:70px;');
